    {
        if (_deepCapsuleSlotHost == null)
        {
            return;
        }

        _deepCapsuleSlotHost.Width = DeepCapsuleSlotViewportWidth(viewportWidth);
        _deepCapsuleSlotHost.Height = PaperLayoutDefaults.CapsuleHeight;
