        _deepCapsuleSlotDragScale.BeginAnimation(ScaleTransform.ScaleXProperty, null);
        _deepCapsuleSlotDragScale.BeginAnimation(ScaleTransform.ScaleYProperty, null);
        if (!animate || !active)
        {
