                else
                {
                    _controller.ReorderDeepCapsule(_paper, DeepCapsuleDropIndexForCurrentPosition());
                }
                return;
            }

            MoveDeepCapsuleToCurrentTarget();
        }
        finally
        {
            _isEndingDeepCapsuleReorderDrag = false;
