    private static void ActivateTrayContextMenu(ContextMenu menu)
    {
        void SetMenuForeground(string phase)
        {
            if (!menu.IsOpen)
            {
                TrayDiagnostics.Write($"menu.foreground.{phase}.skip_closed", TrayMenuDebugState(menu));
                return;
            }

            if (PresentationSource.FromVisual(menu) is HwndSource source)
            {
                var foregroundResult = WindowNative.TrySetForegroundWindow(source.Handle);
                TrayDiagnostics.Write(
                    $"menu.foreground.{phase}.set",
                    $"result={foregroundResult} source={WindowNative.DescribeWindow(source.Handle)} {TrayMenuDebugState(menu)}");
                return;
            }

            TrayDiagnostics.Write(
                $"menu.foreground.{phase}.no_hwnd",
                TrayMenuDebugState(menu));
        }

        void FocusMenu(string phase)
        {
            if (!menu.IsOpen)
            {
                TrayDiagnostics.Write($"menu.focus.{phase}.skip_closed", TrayMenuDebugState(menu));
                return;
            }

            var menuFocus = menu.Focus();
            var keyboardFocus = Keyboard.Focus(menu);
            TrayDiagnostics.Write(
                $"menu.focus.{phase}",
                $"menuFocus={menuFocus} keyboardFocus={keyboardFocus?.GetType().Name ?? "<null>"} {TrayMenuDebugState(menu)}");
        }

        SetMenuForeground("immediate");
        _ = menu.Dispatcher.InvokeAsync(() => FocusMenu("input"), DispatcherPriority.Input);
    }

    private static string TrayMenuDebugState(ContextMenu menu)
    {
        var source = PresentationSource.FromVisual(menu) as HwndSource;
        var sourceDescription = source == null
            ? "source=<null>"
            : $"source={WindowNative.DescribeWindow(source.Handle)}";
        return $"isOpen={menu.IsOpen} items={menu.Items.Count} focusWithin={menu.IsKeyboardFocusWithin} keyboardFocused={Keyboard.FocusedElement?.GetType().Name ?? "<null>"} {sourceDescription}";
    }

