using System.IO;
using System.Text;

namespace PaperTodo;

internal static class TrayDiagnostics
{
    private const long MaxLogBytes = 1024 * 1024;
    private static readonly object Gate = new();

    private static string LogPath => Path.Combine(AppContext.BaseDirectory, "tray-debug.log");
    private static string MarkerPath => Path.Combine(AppContext.BaseDirectory, "tray-debug.enabled");

    public static bool IsEnabled
    {
        get
        {
            try
            {
                return IsTruthy(Environment.GetEnvironmentVariable("PAPERTODO_TRAY_DEBUG")) ||
                    File.Exists(MarkerPath);
            }
            catch
            {
                return false;
            }
        }
    }

    public static void Write(string stage, string? details = null)
    {
        if (!IsEnabled)
        {
            return;
        }

        try
        {
            lock (Gate)
            {
                TrimIfNeeded();
                var line = new StringBuilder();
                line.Append(DateTimeOffset.Now.ToString("O"));
                line.Append(" tid=");
                line.Append(Environment.CurrentManagedThreadId);
                line.Append(" stage=");
                line.Append(stage);
                if (!string.IsNullOrWhiteSpace(details))
                {
                    line.Append(" ");
                    line.Append(details);
                }
                line.Append(" foreground=");
                line.Append(WindowNative.DescribeForegroundWindow());
                line.AppendLine();

                File.AppendAllText(LogPath, line.ToString(), Encoding.UTF8);
            }
        }
        catch
        {
            // Diagnostics must never affect tray or capsule interaction.
        }
    }

    private static bool IsTruthy(string? value)
    {
        return string.Equals(value, "1", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(value, "true", StringComparison.OrdinalIgnoreCase) ||
            string.Equals(value, "yes", StringComparison.OrdinalIgnoreCase);
    }

    private static void TrimIfNeeded()
    {
        var file = new FileInfo(LogPath);
        if (!file.Exists || file.Length < MaxLogBytes)
        {
            return;
        }

        File.WriteAllText(LogPath, string.Empty, Encoding.UTF8);
    }
}

